export function nextGeneration(cells: Cell[]): Cell[] {
  const key = ([x, y]: Cell) => `${x},${y}`;
  const liveSet = new Set(cells.map(key));
  const candidates = new Map<string, Cell>();
  for (const [x, y] of cells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        const c: Cell = [x + dx, y + dy];
        candidates.set(key(c), c);
      }
    }
  }
  const result: Cell[] = [];
  for (const cell of candidates.values()) {
    const neighbors = countLiveNeighbors(cell, cells);
    const isAlive = liveSet.has(key(cell));
    if (isAlive && (neighbors === 2 || neighbors === 3)) result.push(cell);
    else if (!isAlive && neighbors === 3) result.push(cell);
  }
  return result;
}

